import{c as a,a7 as r,y as i,B as t}from"./chunks/framework.3cjvm90C.js";const f=JSON.parse('{"title":"零和博弈与联赛训练","description":"介绍零和博弈中的联赛训练机制与自博弈策略","frontmatter":{"title":"零和博弈与联赛训练","description":"介绍零和博弈中的联赛训练机制与自博弈策略"},"headers":[],"relativePath":"rlwiki/papers/league.md","filePath":"rlwiki/papers/league.md","lastUpdated":1782448598000}'),l={name:"rlwiki/papers/league.md"};function n(o,e,p,h,g,s){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="零和博弈" tabindex="-1">零和博弈 <a class="header-anchor" href="#零和博弈" aria-label="Permalink to “零和博弈”">​</a></h1><h2 id="问题定义与研究动机" tabindex="-1">问题定义与研究动机 <a class="header-anchor" href="#问题定义与研究动机" aria-label="Permalink to “问题定义与研究动机”">​</a></h2><p>零和博弈，又称零和游戏，是博弈论的一个经典概念，意为所有博弈方的利益之和为零的博弈。零和博弈根据参与者的人数分类可分为双人零和博弈和多人零和博弈。 经典的双人零和博弈场景如石头剪刀布，其中一方获胜必然存在另一方失败，意味着当其中的一方收益增加，必然会带来其他方等量的损失。 在双人零和博弈的研究中，学界普遍认为，其研究难点在于如何找到这一问题的解，也就是 Nash 均衡解（Nash Equilibrium Solution）。</p><h2 id="研究历程" tabindex="-1">研究历程 <a class="header-anchor" href="#研究历程" aria-label="Permalink to “研究历程”">​</a></h2><p>随着学者们对于零和博弈方向的研究深入，主要有以下几个发展阶段：</p><p><strong>1. 自我博弈( Self-Play, SP)</strong></p><p>自我博弈指的是训练中自己和自己对抗，常用于解决棋类游戏和建立一般游戏的基准。像围棋 AI AlphaZero 和 Dota2 的 AI OpenAI Five，则没有利用任何人类数据，只通过自我博弈便达到了超越人类的水平。 虽然 Self-Play 可以在很多游戏类型中达到超越人类水平的表现，但也有其不足之处。比如在石头剪刀布这一环境中假定人类的策略是只出剪刀，那么 Self-Play 模型会以一个类似剪刀，石头，布的顺序无限循环往复作为策略。</p><p><strong>2. 虚拟自我博弈( Fictious Self-Play, FSP)</strong> [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id12" target="_blank" rel="noreferrer">1]</a>]</p><p>为了解决上述 Self-Play 局限性问题， FSP 在训练中引入了训练智能体的过往版本加入训练，在 Self-Play 的基础上，还会随机的以相同概率挑选过往版本的智能体对抗，这种训练方式被称为虚拟自我博弈。因为对手池的多样性，不管我们的初始策略是什么， FSP 都会收敛到均匀随机出石头剪刀布的混合策略，同时该策略这也是此问题的纳什均衡解。</p><p><strong>3. 优先虚拟自我博弈( Prioritised Fictious Self-Play, PFSP)</strong> [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id13" target="_blank" rel="noreferrer">2]</a>]</p><p>PFSP( Prioritised Fictious Self-Play)是在 FSP 的基础上，依照训练智能体和历史智能体之间的对战胜率分配对手，增加训练智能体对战胜率低的历史智能体的出现频率，从而达到更快的收敛速度，这种训练方式被称为优先虚拟自我博弈。星际争霸 2 的 AI AlphaStar [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id14" target="_blank" rel="noreferrer">3]</a>] 便采用了 PFSP 来辅助训练。</p><p><img src="https://opendilab.github.io/DI-engine/_images/pfsp.png" alt="../_images/pfsp.png"></p><h2 id="未来展望" tabindex="-1">未来展望 <a class="header-anchor" href="#未来展望" aria-label="Permalink to “未来展望”">​</a></h2><ol><li>如何设计更为高效的匹配策略，用更少的训练资源，得到更强的智能体。</li></ol><p>在大量工程项目( ALphaStar, TstarBot [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id15" target="_blank" rel="noreferrer">4]</a>] ) 中都有各自的设计，但往往是经验性的（依靠人类的主观判断），很少有在理论上论证为何高效。</p><ol><li>如何考虑多人零和博弈乃至更为一般的多人博弈问题。</li></ol><ul><li>在 Policy-Space Response Oracles [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id16" target="_blank" rel="noreferrer">5]</a>] 这篇文章中提出了多人博弈时的一个求解框架。</li><li>在 Alpha-Rank [[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id17" target="_blank" rel="noreferrer">6]</a>] 这篇文章中，考虑了除纳什均衡之外的另一种解。</li></ul><p><img src="https://opendilab.github.io/DI-engine/_images/psro.png" alt="../_images/psro.png"></p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to “参考文献”">​</a></h2><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id4" target="_blank" rel="noreferrer">1</a>]Heinrich, Johannes, Marc Lanctot, and David Silver. “Fictitious self-play in extensive-form games.” International conference on machine learning. PMLR, 2015.</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id5" target="_blank" rel="noreferrer">2</a>]Lanctot, Marc, et al. “A unified game-theoretic approach to multiagent reinforcement learning.” Advances in neural information processing systems 30 (2017).</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id6" target="_blank" rel="noreferrer">3</a>]Vinyals, Oriol, et al. “Grandmaster level in StarCraft II using multi-agent reinforcement learning.” Nature 575.7782 (2019): 350-354.</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id8" target="_blank" rel="noreferrer">4</a>]Han, Lei, et al. “Tstarbot-x: An open-sourced and comprehensive study for efficient league training in starcraft ii full game.” arXiv preprint arXiv:2011.13729 (2020).</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id9" target="_blank" rel="noreferrer">5</a>]Muller, Paul, et al. “A generalized training approach for multiagent learning.” arXiv preprint arXiv:1909.12823 (2019).</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/league_zh.html#id10" target="_blank" rel="noreferrer">6</a>]Omidshafiei, Shayegan, et al. “α-rank: Multi-agent evaluation by evolution.” Scientific reports 9.1 (2019): 1-29.</p>',25)])])}const u=a(l,[["render",n]]);export{f as __pageData,u as default};
